BEGIN;

CREATE OR REPLACE FUNCTION public.duplicate_as_new_generation(
  p_shot_id uuid,
  p_generation_id uuid,
  p_project_id uuid,
  p_timeline_frame integer,
  p_next_timeline_frame integer DEFAULT NULL,
  p_target_timeline_frame integer DEFAULT NULL
)
RETURNS jsonb
LANGUAGE plpgsql
AS $function$
DECLARE
  v_shot_id uuid;
  v_source_location text;
  v_source_thumbnail_url text;
  v_source_params jsonb := '{}'::jsonb;
  v_new_params jsonb;
  v_new_generation_id uuid;
  v_new_shot_generation_id uuid;
  v_target_timeline_frame integer;
  v_new_timeline_frame integer;
  v_created_at timestamptz;
  v_generation_type text;
  v_offset integer := 1;
BEGIN
  IF auth.role() <> 'service_role' AND NOT EXISTS (
    SELECT 1
    FROM public.projects p
    WHERE p.id = p_project_id
      AND p.user_id = auth.uid()
  ) THEN
    RAISE EXCEPTION 'Not authorized to duplicate generations in this project';
  END IF;

  SELECT s.id
  INTO v_shot_id
  FROM public.shots s
  WHERE s.id = p_shot_id
    AND s.project_id = p_project_id;

  IF v_shot_id IS NULL THEN
    RAISE EXCEPTION 'Shot % was not found in project %', p_shot_id, p_project_id;
  END IF;

  SELECT
    COALESCE(gv.location, g.location),
    COALESCE(gv.thumbnail_url, g.thumbnail_url),
    CASE
      WHEN jsonb_typeof(COALESCE(gv.params, g.params, '{}'::jsonb)) = 'object'
        THEN COALESCE(gv.params, g.params, '{}'::jsonb)
      ELSE '{}'::jsonb
    END
  INTO
    v_source_location,
    v_source_thumbnail_url,
    v_source_params
  FROM public.generations g
  LEFT JOIN public.generation_variants gv ON gv.id = g.primary_variant_id
  WHERE g.id = p_generation_id
    AND g.project_id = p_project_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Generation % was not found in project %', p_generation_id, p_project_id;
  END IF;

  IF v_source_location IS NULL THEN
    RAISE EXCEPTION 'Generation % is missing location', p_generation_id;
  END IF;

  PERFORM pg_advisory_xact_lock(hashtext('duplicate_as_new_generation'), hashtext(p_shot_id::text));

  v_generation_type := CASE
    WHEN v_source_location ~* '\.(mp4|webm|mov)(\?.*)?$' THEN 'video'
    ELSE 'image'
  END;

  v_new_params := v_source_params
    || jsonb_build_object(
      'source', 'timeline_duplicate',
      'source_generation_id', p_generation_id,
      'duplicated_at', statement_timestamp()
    );

  INSERT INTO public.generations (
    project_id,
    type,
    based_on,
    params
  )
  VALUES (
    p_project_id,
    v_generation_type,
    p_generation_id,
    v_new_params
  )
  RETURNING id, created_at
  INTO v_new_generation_id, v_created_at;

  INSERT INTO public.generation_variants (
    generation_id,
    project_id,
    location,
    thumbnail_url,
    is_primary,
    variant_type,
    name,
    params
  )
  VALUES (
    v_new_generation_id,
    p_project_id,
    v_source_location,
    v_source_thumbnail_url,
    TRUE,
    'original',
    'Original',
    v_new_params
  );

  v_target_timeline_frame := CASE
    WHEN p_target_timeline_frame IS NOT NULL THEN p_target_timeline_frame
    WHEN p_next_timeline_frame IS NOT NULL THEN floor((p_timeline_frame + p_next_timeline_frame) / 2.0)::integer
    ELSE p_timeline_frame + 30
  END;

  v_new_timeline_frame := GREATEST(0, round(v_target_timeline_frame::numeric)::integer);

  IF EXISTS (
    SELECT 1
    FROM public.shot_generations sg
    WHERE sg.shot_id = p_shot_id
      AND sg.timeline_frame = v_new_timeline_frame
  ) THEN
    WHILE v_offset < 1000 LOOP
      IF NOT EXISTS (
        SELECT 1
        FROM public.shot_generations sg
        WHERE sg.shot_id = p_shot_id
          AND sg.timeline_frame = v_new_timeline_frame + v_offset
      ) THEN
        v_new_timeline_frame := v_new_timeline_frame + v_offset;
        EXIT;
      END IF;

      IF v_new_timeline_frame - v_offset >= 0 AND NOT EXISTS (
        SELECT 1
        FROM public.shot_generations sg
        WHERE sg.shot_id = p_shot_id
          AND sg.timeline_frame = v_new_timeline_frame - v_offset
      ) THEN
        v_new_timeline_frame := v_new_timeline_frame - v_offset;
        EXIT;
      END IF;

      v_offset := v_offset + 1;
    END LOOP;
  END IF;

  INSERT INTO public.shot_generations (
    shot_id,
    generation_id,
    timeline_frame
  )
  VALUES (
    p_shot_id,
    v_new_generation_id,
    v_new_timeline_frame
  )
  RETURNING id
  INTO v_new_shot_generation_id;

  RETURN jsonb_build_object(
    'new_generation_id', v_new_generation_id,
    'new_shot_generation_id', v_new_shot_generation_id,
    'timeline_frame', v_new_timeline_frame,
    'location', v_source_location,
    'thumbnail_url', COALESCE(v_source_thumbnail_url, v_source_location),
    'type', v_generation_type,
    'params', v_new_params,
    'created_at', v_created_at
  );
END;
$function$;

GRANT EXECUTE ON FUNCTION public.duplicate_as_new_generation(uuid, uuid, uuid, integer, integer, integer) TO authenticated;

COMMENT ON FUNCTION public.duplicate_as_new_generation(uuid, uuid, uuid, integer, integer, integer) IS
'Duplicates a generation into the same shot atomically, creates a new primary variant, resolves timeline collisions in-function, and returns the hydrated data needed for direct cache updates.';

COMMIT;

/**
 * Duplicate an image in a shot by creating a NEW generation via an atomic RPC.
 * Extracted from useShotGenerationMutations for single-responsibility.
 */

import { useMutation, useQueryClient } from '@tanstack/react-query';
import { getSupabaseClient as supabase } from '@/integrations/supabase/client';
import { toast } from '@/shared/components/ui/runtime/sonner';
import { enqueueGenerationsInvalidation } from '@/shared/hooks/invalidation';
import { invalidateShotsQueries } from '@/shared/hooks/shots/cacheUtils';
import { queryKeys } from '@/shared/lib/queryKeys';

interface DuplicateAsNewGenerationInput {
  shot_id: string;
  generation_id: string;
  project_id: string;
  timeline_frame: number;
  next_timeline_frame?: number;
  /** Explicit target frame - bypasses midpoint/+30 calculation */
  target_timeline_frame?: number;
}

interface DuplicateAsNewGenerationResult {
  created_at: string;
  location: string;
  thumbnail_url: string | null;
  type: string | null;
  params: unknown;
  shot_id: string;
  original_generation_id: string;
  new_generation_id: string;
  new_shot_generation_id: string;
  timeline_frame: number;
  project_id: string;
}

async function duplicateAsNewGeneration(
  input: DuplicateAsNewGenerationInput
): Promise<DuplicateAsNewGenerationResult> {
  const { data, error } = await supabase().rpc('duplicate_as_new_generation', {
      p_shot_id: input.shot_id,
      p_generation_id: input.generation_id,
      p_project_id: input.project_id,
      p_timeline_frame: input.timeline_frame,
      p_next_timeline_frame: input.next_timeline_frame,
      p_target_timeline_frame: input.target_timeline_frame,
    })
    .single();

  if (error) {
    throw error;
  }

  const typedData = data as Partial<DuplicateAsNewGenerationResult> | null;
  if (
    !typedData?.new_generation_id
    || !typedData.new_shot_generation_id
    || typeof typedData.timeline_frame !== 'number'
    || typeof typedData.location !== 'string'
    || typeof typedData.created_at !== 'string'
  ) {
    throw new Error('Failed to duplicate image');
  }

  return {
    shot_id: input.shot_id,
    original_generation_id: input.generation_id,
    new_generation_id: typedData.new_generation_id,
    new_shot_generation_id: typedData.new_shot_generation_id,
    timeline_frame: typedData.timeline_frame,
    project_id: input.project_id,
    location: typedData.location,
    thumbnail_url: typedData.thumbnail_url ?? null,
    type: typedData.type ?? null,
    params: typedData.params,
    created_at: typedData.created_at,
  };
}

export const useDuplicateAsNewGeneration = () => {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: duplicateAsNewGeneration,
    onSuccess: (data) => {
      enqueueGenerationsInvalidation(queryClient, data.shot_id, {
        reason: 'duplicate-as-new-generation',
        scope: 'all',
        includeShots: false,
        projectId: data.project_id,
        includeProjectUnified: true,
      });
      invalidateShotsQueries(queryClient, data.project_id, { refetchType: 'inactive' });
      queryClient.invalidateQueries({
        queryKey: queryKeys.generations.derivedGenerations(data.original_generation_id),
      });
      queryClient.invalidateQueries({
        queryKey: queryKeys.segments.parents(data.shot_id, data.project_id),
      });
    },
    onError: (error: Error) => {
      toast.error(`Failed to duplicate image: ${error.message}`);
    },
  });
};

/** Default/max spacing when no existing items to calculate average from */
export const DEFAULT_FRAME_SPACING = 50;

/** Minimum spacing to use even if average is lower (prevents overly tight timelines) */
const MIN_FRAME_SPACING = 10;

export const calculateAverageSpacing = (
  existingFrames: number[],
  defaultSpacing: number = DEFAULT_FRAME_SPACING
): number => {
  // Need at least 2 items to calculate spacing
  if (existingFrames.length < 2) {
    return defaultSpacing;
  }

  const sortedFrames = [...existingFrames].sort((a, b) => a - b);
  const minFrame = sortedFrames[0];
  const maxFrame = sortedFrames[sortedFrames.length - 1];

  const totalSpan = maxFrame - minFrame;
  const numGaps = sortedFrames.length - 1;
  const averageSpacing = Math.round(totalSpan / numGaps);

  return Math.min(DEFAULT_FRAME_SPACING, Math.max(MIN_FRAME_SPACING, averageSpacing));
};

export const ensureUniqueFrame = (
  targetFrame: number,
  existingFrames: number[],
  minGap: number = 1
): number => {
  // Normalize to integer
  const frame = Math.max(0, Math.round(targetFrame));

  // If no collision, return as-is
  if (!existingFrames.includes(frame)) {
    return frame;
  }

  let offset = 1;
  const maxOffset = 1000; // Safety limit

  while (offset < maxOffset) {
    const higher = frame + offset;
    if (!existingFrames.includes(higher)) {
      return higher;
    }

    const lower = frame - offset;
    if (lower >= 0 && !existingFrames.includes(lower)) {
      return lower;
    }

    offset += minGap;
  }

  const maxFrame = existingFrames.length > 0 ? Math.max(...existingFrames) : 0;
  const fallback = maxFrame + DEFAULT_FRAME_SPACING;
  return fallback;
};

interface DuplicateFrameOptions {
  currentFrame: number;
  nextFrame?: number | null;
  existingFrames: number[];
  singleItemTrailingFrame?: number | null;
  isSingleItem: boolean;
  defaultDuplicateGap?: number;
  defaultSingleItemTrailingGap?: number;
}

export const calculateDuplicateFrame = (options: DuplicateFrameOptions): number => {
  // For optimistic/preview use. For duplicate_as_new_generation, SQL is authoritative:
  // pass timeline_frame + next_timeline_frame instead of pre-computing target_timeline_frame.
  const {
    currentFrame,
    nextFrame,
    existingFrames,
    singleItemTrailingFrame,
    isSingleItem,
    defaultDuplicateGap = 30,
    defaultSingleItemTrailingGap = 49,
  } = options;

  const baseTarget = isSingleItem
    ? (singleItemTrailingFrame ?? (currentFrame + defaultSingleItemTrailingGap))
    : (typeof nextFrame === 'number'
      ? Math.floor((currentFrame + nextFrame) / 2)
      : currentFrame + defaultDuplicateGap);

  return ensureUniqueFrame(baseTarget, existingFrames);
};

export const calculateFrameForIndex = (
  index: number,
  existingFrames: number[],
  explicitSpacing?: number
): number => {
  const sortedFrames = [...existingFrames].sort((a, b) => a - b);

  let targetFrame: number;

  if (sortedFrames.length === 0) {
    // Empty timeline - start at 0
    targetFrame = 0;
  } else if (index === 0) {
    // Inserting at beginning - use half of first frame
    const firstFrame = sortedFrames[0];
    targetFrame = Math.max(0, Math.floor(firstFrame / 2));
  } else if (index >= sortedFrames.length) {
    // Inserting at end - use average spacing or explicit
    const spacing = explicitSpacing ?? calculateAverageSpacing(sortedFrames);
    const lastFrame = sortedFrames[sortedFrames.length - 1];
    targetFrame = lastFrame + spacing;
  } else {
    // Inserting in middle - use midpoint between neighbors
    const prevFrame = sortedFrames[index - 1];
    const nextFrame = sortedFrames[index];
    targetFrame = Math.floor((prevFrame + nextFrame) / 2);
  }

  // Ensure the calculated frame is unique
  return ensureUniqueFrame(targetFrame, sortedFrames);
};

export const calculateNextAvailableFrame = (
  existingFrames: number[],
  explicitSpacing?: number
): number => {
  if (existingFrames.length === 0) {
    return 0;
  }

  const spacing = explicitSpacing ?? calculateAverageSpacing(existingFrames);

  const maxFrame = Math.max(...existingFrames);
  const targetFrame = maxFrame + spacing;

  return ensureUniqueFrame(targetFrame, existingFrames);
};

export const extractExistingFrames = (
  items: Array<{ timeline_frame?: number | null; type?: string | null }>
): number[] => {
  return items
    .filter(item => {
      // Filter out videos
      if (item.type === 'video') return false;
      // Filter out null/undefined frames
      if (item.timeline_frame == null) return false;
      // Filter out unpositioned items (timeline_frame === -1)
      if (item.timeline_frame === -1) return false;
      return true;
    })
    .map(item => item.timeline_frame as number);
};

