    if (!resolvedConfig) {
      return {};
    }

    return resolvedConfig.clips.reduce<Record<string, string>>((acc, clip) => {
      if (clip.clipType === 'text' || !clip.assetEntry?.type?.startsWith('image')) {
        return acc;
      }

      acc[clip.id] = clip.assetEntry.src;
      return acc;
    }, {});
  }, [resolvedConfig]);

  const handleClipSelect = useCallback((clipId: string, trackId: string) => {
    selectClip(clipId);
    setSelectedTrackId(trackId);
  }, [selectClip, setSelectedTrackId]);

  const pixelsPerSecond = scaleWidth / scale;
  const shotGroups = useShotGroups(
    data?.rows ?? [],
    data?.meta ?? EMPTY_CLIP_META,
    data?.registry ?? EMPTY_ASSET_REGISTRY,
    shots,
  );
  const assetGenerationMap = useMemo<Record<string, string>>(() => {
    const assets = data?.registry?.assets;
    if (!assets) {
      return EMPTY_ASSET_GENERATION_MAP;
    }

    return Object.entries(assets).reduce<Record<string, string>>((acc, [assetKey, assetEntry]) => {
      if (typeof assetEntry?.generationId === 'string' && assetEntry.generationId.length > 0) {
        acc[assetKey] = assetEntry.generationId;
      }
      return acc;
    }, {});

import type { SelectedClipPayload, SupabaseAdmin, TimelineState, ToolResult } from "../types.ts";
import { asTrimmedString, isRecord } from "../utils.ts";
import { findShotForGenerations, resolveClipGenerationIds } from "./clips.ts";

export async function executeDuplicateGeneration(
  args: Record<string, unknown>,
  timelineState: TimelineState,
  selectedClips: SelectedClipPayload[] | undefined,
  supabaseAdmin: SupabaseAdmin,
): Promise<Pick<ToolResult, "result">> {
  const generationId = asTrimmedString(args.generation_id);
  if (!generationId) return { result: "duplicate_generation requires generation_id." };

  const selectedGenerationIds = resolveClipGenerationIds(selectedClips ?? [], timelineState.registry, timelineState.config);
  const lookupGenerationIds = Array.from(new Set([...selectedGenerationIds, generationId]));
  let selectedShotId: string | null = null;
  if (lookupGenerationIds.length) {
    try {
      selectedShotId = await findShotForGenerations(supabaseAdmin, lookupGenerationIds);
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      return { result: `Failed to resolve a source shot for ${generationId}: ${message}` };
    }
  }

  const { data: shotGeneration, error: shotGenerationError } = await supabaseAdmin
    .from("shot_generations")
    .select("shot_id, timeline_frame")
    .eq("generation_id", generationId)
    .maybeSingle();
  if (shotGenerationError) {
    return { result: `Failed to load source generation ${generationId}: ${shotGenerationError.message}` };
  }
  if (!isRecord(shotGeneration)) {
    return { result: `Generation ${generationId} was not found in shot_generations.` };
  }

  const shotId = selectedShotId ?? asTrimmedString(shotGeneration.shot_id);
  const sourceTimelineFrame = typeof shotGeneration.timeline_frame === "number" ? shotGeneration.timeline_frame : null;
  if (!shotId) {
    return { result: `Could not find a shot for generation ${generationId}. Select the source clip or ensure it is linked to a shot.` };
  }
  if (sourceTimelineFrame === null) {
    return { result: `Generation ${generationId} is missing a source timeline_frame.` };
  }

  const { data, error } = await supabaseAdmin.rpc("duplicate_as_new_generation", {
    p_shot_id: shotId,
    p_generation_id: generationId,
    p_project_id: timelineState.projectId,
    p_timeline_frame: sourceTimelineFrame,
  }).maybeSingle();
  if (error) {
    return { result: `Failed to duplicate generation ${generationId}: ${error.message}` };
  }
  if (!isRecord(data)) {
    return { result: `duplicate_as_new_generation returned an invalid response for ${generationId}.` };
  }

  const newGenerationId = asTrimmedString(data.new_generation_id);
  const location = asTrimmedString(data.location);
  const mediaType = asTrimmedString(data.type) ?? "unknown";
  if (!newGenerationId || !location) {
    return { result: `duplicate_as_new_generation did not return the new generation details for ${generationId}.` };
  }

  return {
    result: `Duplicated ${generationId} -> ${newGenerationId}. Asset: ${location} (type: ${mediaType}). Use new_generation_id as based_on in create_task, or later with add-media to place on the timeline.`,
  };
}

  }, {});
}, [data?.registry?.assets]);
const stableAssetGenerationMap = useStableValue(assetGenerationMap);

const selectionShotCreationState = useMemo(() => {
  if (!data?.rows || !data?.meta) {
    return { canCreateShot: false, generationIds: [] as string[] };
  }

  return resolveSelectedGenerationIdsForShotCreation({
    rows: data.rows,
    meta: data.meta,
    assetGenerationMap: stableAssetGenerationMap,
    selectedClipIds,
  });
}, [data?.rows, data?.meta, stableAssetGenerationMap, selectedClipIds]);

const existingShotsForSelection = useMemo(() => {
  if (selectionShotCreationState.generationIds.length === 0 || !shots?.length) {
    return [] as Shot[];
  }

  return shots.filter((shot) => {
    const shotGenerationIds = new Set(
      (shot.images ?? [])
        .map((image) => image.generation_id)
        .filter((generationId): generationId is string => typeof generationId === 'string' && generationId.length > 0),
    );

    return selectionShotCreationState.generationIds.every((generationId) => shotGenerationIds.has(generationId));
  });
}, [shots, selectionShotCreationState.generationIds]);

const handleCreateShotFromSelection = useCallback(async (): Promise<Shot | null> => {
  console.log('[ShotCreate] handleCreateShotFromSelection', {
    canCreateShot: selectionShotCreationState.canCreateShot,
    generationIds: selectionShotCreationState.generationIds,
  });
  if (!selectionShotCreationState.canCreateShot) {
    return null;
  }

  const result = await createShot({ generationIds: selectionShotCreationState.generationIds });
  console.log('[ShotCreate] createShot result', result);
  if (result?.shot) {
    return result.shot;
  }
  return null;
}, [createShot, selectionShotCreationState]);

const handleGenerateVideoFromSelection = useCallback(async () => {
  if (!selectionShotCreationState.canCreateShot) {
    return;
  }

  const result = await createShot({ generationIds: selectionShotCreationState.generationIds });
  if (!result?.shotId) {
    return;
  }

  const createdShot = result.shot ?? shots?.find((shot) => shot.id === result.shotId) ?? null;
  if (createdShot) {
    setVideoModalShot(createdShot);
  }
}, [createShot, selectionShotCreationState, shots]);

const handleNavigateToShot = useCallback((shot: Shot) => {
