import { useEffect } from 'react';
import type { GenerationRow } from '@/domains/generation/types';
import { useTimelinePositions } from './timeline-core/useTimelinePositions';
import { runSerializedTimelineWrite } from '@/shared/lib/timelineWriteQueue';

interface PositionManagementProps {
  shotId: string;
  shotGenerations: GenerationRow[];
  frameSpacing: number;
  isDragInProgress: boolean;
  onFramePositionsChange?: (framePositions: Map<string, number>) => void;
}

export function usePositionManagement({
  shotId,
  shotGenerations,
  frameSpacing,
  isDragInProgress,
  onFramePositionsChange,
}: PositionManagementProps) {

  const positionSystem = useTimelinePositions({
    shotId,
    shotGenerations,
    frameSpacing,
    onPositionsChange: onFramePositionsChange,
  });

  const { lockPositions, unlockPositions } = positionSystem;
  useEffect(() => {
    if (isDragInProgress) {
      lockPositions();
    } else {
      unlockPositions();
    }
  }, [isDragInProgress, lockPositions, unlockPositions]);

  const updatePositions = async (newPositions: Map<string, number>) => {
    const preAppliedRollback = positionSystem.applyOptimisticPositionUpdate(newPositions);

    await runSerializedTimelineWrite(
      shotId,
      'timeline-drag-positions',
      async (signal) => {
        await positionSystem.updatePositions(newPositions, {
          operation: 'drag',
          skipOptimistic: true,
          externalRollback: preAppliedRollback,
          signal,
        });
      },

    );
  };

  return {
    positions: positionSystem.positions,
    updatePositions,
  };
}

import type { GenerationRow } from '@/domains/generation/types';

export type PositionStatus =
  | { type: 'idle' }
  | { type: 'updating'; operationId: string; description: string }
  | { type: 'error'; message: string; canRetry: boolean };

export interface UseTimelinePositionsProps {
  shotId: string | null;
  shotGenerations: GenerationRow[];
  frameSpacing?: number;
  onPositionsChange?: (positions: Map<string, number>) => void;
}

export interface UpdateOptions {
  operation?: 'drag' | 'drop' | 'reorder' | 'reset';
  skipOptimistic?: boolean;
  skipDatabase?: boolean;
  metadata?: Record<string, unknown>;
  /**
   * When optimistic update was applied externally (before the write queue),
   * pass its rollback function here so updatePositions can roll back on error.
   */
  externalRollback?: (() => void) | null;
  signal?: AbortSignal;
}

export interface UseTimelinePositionsReturn {
  // The single source of truth for positions
  positions: Map<string, number>;

  // Status for UI feedback
  status: PositionStatus;
  isUpdating: boolean;
  isIdle: boolean;

  // Core operations
  updatePositions: (newPositions: Map<string, number>, options?: UpdateOptions) => Promise<void>;
  addItemsAtPositions: (items: Array<{ id: string; position: number }>) => () => void;
  removeItems: (ids: string[]) => () => void;

  /**
   * Apply optimistic visual update immediately without entering the write queue
   * or touching the DB. Returns a rollback function (or null if nothing changed).
   * Intended to be called BEFORE runSerializedTimelineWrite, with the returned
   * rollback passed as UpdateOptions.externalRollback so updatePositions can
   * roll back on DB error.
   */
  applyOptimisticPositionUpdate: (newPositions: Map<string, number>) => (() => void) | null;

  // Sync control
  syncFromDatabase: () => void;
  lockPositions: () => void;
  unlockPositions: () => void;

  // Helpers
  getPosition: (id: string) => number | undefined;
  hasPosition: (id: string) => boolean;
  hasPendingUpdate: (id: string) => boolean;
}

const clearPendingUpdates = useCallback((ids: string[]) => {
  ids.forEach(id => pendingUpdatesRef.current.delete(id));
  snapshotRef.current = null;
}, [pendingUpdatesRef, snapshotRef]);

/**
 * Update positions with optimistic UI and database persistence.
 */
const updatePositions = useCallback(async (
  newPositions: Map<string, number>,
  options: UpdateOptions = {},
) => {
  const {
    operation = 'reorder',
    skipOptimistic = false,
    skipDatabase = false,
    metadata = {},
    externalRollback,
    signal,
  } = options;

  if (!shotId) {
    return;
  }

  const shouldQuantize = operation !== 'drag';
  const quantizedPositions = shouldQuantize ? quantizePositions(newPositions) : new Map(newPositions);

  const operationId = `op-${++operationIdRef.current}-${operation}`;

  const basePositions =
    skipOptimistic && snapshotRef.current ? snapshotRef.current : positionsRef.current;
  const changes = detectPositionChanges(basePositions, quantizedPositions);

  const trailingRemoved = positionsRef.current.has(TRAILING_ENDPOINT_KEY) && !quantizedPositions.has(TRAILING_ENDPOINT_KEY);

  if (changes.length === 0 && !trailingRemoved) {
    return;
  }

  if (hasDuplicatePositionValues(quantizedPositions)) {
    toast.error('Position conflict detected - operation cancelled');
    return;
  }

  let rollback: (() => void) | null = null;
  if (!skipOptimistic) {
    const optimisticUpdates = changes.map(c => ({
      id: c.id,
      position: c.newPos,
      operation: (c.oldPos === null ? 'add' : 'move') as 'add' | 'move' | 'remove',
    }));
    if (trailingRemoved) {
      optimisticUpdates.push({
        id: TRAILING_ENDPOINT_KEY,
        position: 0,
        operation: 'remove',
      });
    }
    rollback = applyOptimistic(optimisticUpdates);
  } else if (externalRollback !== undefined) {
    rollback = externalRollback;
  }

  if (skipDatabase) {
    clearPendingUpdates(changes.map(c => c.id));
    return;
  }

  writeInFlightRef.current++;

  isUpdatingRef.current = true;
  setStatus({
    type: 'updating',
    operationId,
    description: `${operation}: ${changes.length} items`,
  });

  isLockedRef.current = true;

  try {

      type: 'image' as const,
      created_at: new Date().toISOString(),
      starred: false,
      name: file.name,
      based_on: null,
      params: {},
      shot_data: { [currentShot.id]: [positions[index]] },
      _optimistic: true,
      _uploading: true
    };
  });

  // Add optimistic items to cache
  queryClientRef.current.setQueryData(
    generationQueryKeys.byShot(currentShot.id),
    [...previousFastGens, ...optimisticItems]
  );

  // 3. Crop images
  const processedFiles = await cropImagesToShotAspectRatio(
    files,
    currentShot,
    currentProjectId,
    projectsRef.current,
    uploadSettingsRef.current
  );

  // 4. Upload with positions
  const result = await handleExternalImageDropMutationRef.current.mutateAsync({
    imageFiles: processedFiles,
    targetShotId: currentShot.id,
    currentProjectQueryKey: currentProjectId,
    currentShotCount: 0,
    skipAutoPosition: false,
    positions: positions,
    skipOptimistic: true
  });

  if (!result?.generationIds?.length) {
    return;
  }

  // 5. If positions weren't set by the upload, set them now (fallback)
  const { data: checkData } = await supabase().from('shot_generations')
    .select('id, timeline_frame')
    .eq('shot_id', currentShot.id)
    .in('generation_id', result.generationIds)
    .limit(1);

  if (checkData?.[0]?.timeline_frame === null) {
    await persistTimelinePositions(
      currentShot.id,
      result.generationIds,
      startFrame,
      1 // Use 1 frame spacing for batch mode
    );
  }

  // Demote orphaned video variants now that new images are in place
  await demoteOrphanedVariantsRef.current(currentShot.id, 'image-add');

} catch (error) {
  normalizeAndPresentError(error, { context: 'BatchDrop', toastTitle: 'Failed to add images' });

  // Remove optimistic items on error
